import{_ as o,c as t,o as s,ag as n}from"./chunks/framework.DVUBUV_u.js";const d=JSON.parse('{"title":"Избранное","description":"","frontmatter":{"title":"Избранное"},"headers":[],"relativePath":"ru/props/favorite.md","filePath":"ru/props/favorite.md"}'),a={name:"ru/props/favorite.md"};function e(i,r,l,g,p,h){return s(),t("div",null,[...r[0]||(r[0]=[n('<h1 id="избранное-props" tabindex="-1">Избранное (Props) <a class="header-anchor" href="#избранное-props" aria-label="Permalink to &quot;Избранное (Props)&quot;">​</a></h1><p><strong>Избранное</strong> в разделе <strong>Props</strong> — это сохраняемый список <strong>компонентов</strong>, к которым можно быстро возвращаться между сессиями работы с инспектором. Отмеченные строки поднимаются <strong>в начало</strong> таблицы, рядом с именем отображается <strong>звезда</strong>, а в шапке доступен счётчик найденных избранных на текущем экране.</p><p>Общее описание вкладки Props: <a href="/docs/ru/props/general.html">Основные возможности</a>.</p><p><strong>Избранное для Pinia</strong> — отдельный список на вкладке <strong>Stores</strong> и в настройках <strong>Options → Pinia</strong>; здесь описаны только <strong>компоненты Vue</strong>.</p><hr><h2 id="где-добавить-и-убрать" tabindex="-1">Где добавить и убрать <a class="header-anchor" href="#где-добавить-и-убрать" aria-label="Permalink to &quot;Где добавить и убрать&quot;">​</a></h2><p>Добавить компонент в избранное можно несколькими способами.</p><ul><li><strong>В карточке компонента</strong> (детальный просмотр) — в заголовке доступна кнопка <strong>звезды</strong>, которая включает или снимает признак избранного для текущего компонента.</li><li><strong>Через контекстное меню строки в таблице Props</strong> — команда добавления или удаления из избранного доступна среди действий над выбранным компонентом.</li><li><strong>В таблице Props</strong> — быстрый клик по области <strong>звезды</strong> у строки также переключает избранное, даже если иконка ещё не отображается постоянно.</li><li><strong>В Options</strong> — секция <strong>Favorites</strong> в блоке настроек <strong>Props</strong> позволяет просматривать сохранённые записи, удалять их из списка и переходить к выбранному компоненту для просмотра деталей.</li></ul><p>После изменения списка таблица обычно <strong>пересортировывается</strong>: отмеченные компоненты перемещаются выше остальных (если это не противоречит текущим фильтрам поиска).</p><hr><h2 id="что-именно-сохраняется" tabindex="-1">Что именно сохраняется <a class="header-anchor" href="#что-именно-сохраняется" aria-label="Permalink to &quot;Что именно сохраняется&quot;">​</a></h2><p>Для каждой записи хранится, среди прочего:</p><ul><li><strong>имя компонента</strong>;</li><li><strong>идентификатор</strong> для сопоставления со строкой в дереве (в том числе форма с привязкой к корневому DOM-элементу: тег и классы);</li><li>при необходимости <strong>внутренний идентификатор узла</strong> текущей сессии (<strong>nodeId</strong>) — чтобы различать экземпляры с одинаковым именем и похожей разметкой;</li><li><strong>время добавления</strong> (для отображения в списке настроек).</li></ul><p>Это позволяет списку сохраняться после <strong>перезагрузки страницы</strong>: при следующем построении дерева инспектор повторно ищет компонент по сохранённым признакам.</p><hr><h2 id="как-выполняется-сопоставление" tabindex="-1">Как выполняется сопоставление <a class="header-anchor" href="#как-выполняется-сопоставление" aria-label="Permalink to &quot;Как выполняется сопоставление&quot;">​</a></h2><p>При открытии дерева и обновлении состояния избранного используется <strong>устойчивое сравнение идентификаторов</strong>.</p><ul><li>Если сохранён идентификатор в форме <strong>числового uid текущей сессии</strong>, совпадение возможно <strong>только в пределах текущего жизненного цикла дерева</strong> (после полного пересоздания uid изменится).</li><li>Для записей с <strong>именем компонента и сигнатурой корневого элемента</strong> (тег, классы и т.д.) сопоставление опирается на эти <strong>стабильные признаки</strong>, а не на внутренний путь в дереве Vue.</li></ul><p>Для старых записей, где сохранён только <strong>uid сессии</strong>, инспектор дополнительно может использовать <strong>метаданные компонента</strong> (имя, тег, класс), чтобы восстановить соответствие после перезагрузки.</p><p>Если на странице появляется <strong>несколько похожих кандидатов</strong>, сопоставление может выбрать другой экземпляр; в таком случае рекомендуется снять признак избранного и добавить компонент заново уже с актуального узла.</p><hr><h2 id="счетчик-в-шапке" tabindex="-1">Счётчик в шапке <a class="header-anchor" href="#счетчик-в-шапке" aria-label="Permalink to &quot;Счётчик в шапке&quot;">​</a></h2><p>Рядом с полем поиска отображается бейдж вида <strong>«найдено / всего»</strong>: сколько избранных компонентов сейчас видно с учётом активного фильтра и сколько записей всего сохранено в списке.</p><p>Клик по бейджу может использоваться как быстрый переход в <strong>Options</strong> к секции избранного.</p><hr><h2 id="практические-советы" tabindex="-1">Практические советы <a class="header-anchor" href="#практические-советы" aria-label="Permalink to &quot;Практические советы&quot;">​</a></h2><ul><li>Используйте избранное для <strong>опорных компонентов</strong>: шапки приложения, часто проверяемых виджетов, проблемных зон интерфейса.</li><li>После <strong>изменений в структуре DOM</strong> полезно проверить, что избранное всё ещё связано с нужным экземпляром.</li><li>Избранное <strong>не влияет</strong> на выполнение приложения и не связано с <strong>чёрным списком</strong> компонентов — это независимые механизмы.</li></ul><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/ru/props/general.html">Основные возможности Props</a></li><li><a href="/docs/ru/props/blacklist.html">Чёрный список</a></li><li><a href="/docs/ru/options/customize.html">Персонализация / настройки</a></li><li><a href="/docs/ru/store/general.html">Основные возможности Store (Pinia)</a> — избранное для store настраивается отдельно</li></ul>',30)])])}const c=o(a,[["render",e]]);export{d as __pageData,c as default};
